import{_ as a,o as t,c as i,a0 as s}from"./chunks/framework.jwovEGr5.js";const u=JSON.parse('{"title":"Build & Release Guide (Windows & Android)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/build-guide.md","filePath":"guide/build-guide.md"}'),l={name:"guide/build-guide.md"};function n(d,e,r,o,p,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="build-release-guide-windows-android" tabindex="-1">Build &amp; Release Guide (Windows &amp; Android) <a class="header-anchor" href="#build-release-guide-windows-android" aria-label="Permalink to &quot;Build &amp; Release Guide (Windows &amp; Android)&quot;">​</a></h1><p>Instructions to compile frontend assets and package the executable/installer files.</p><hr><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><ul><li><strong>Node.js &amp; npm</strong> (v18+)</li><li><strong>Git</strong></li><li><strong>PowerShell</strong> or similar command-line shell</li></ul><h3 id="android-tv-specifics" tabindex="-1">Android TV Specifics <a class="header-anchor" href="#android-tv-specifics" aria-label="Permalink to &quot;Android TV Specifics&quot;">​</a></h3><ul><li><strong>Java JDK 17</strong></li><li><strong>Android SDK / Android Studio</strong></li><li><strong>ADB (Android Debug Bridge)</strong></li></ul><hr><h2 id="setup-compilation" tabindex="-1">Setup &amp; Compilation <a class="header-anchor" href="#setup-compilation" aria-label="Permalink to &quot;Setup &amp; Compilation&quot;">​</a></h2><p>First, initialize dependencies and compile modern frontend TS files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:all</span></span></code></pre></div><ul><li><code>npm run build:all</code> cleans builds, transpiles TypeScript, bundles the browser architecture layer, and outputs Preact SPA artifacts to <code>app/src/main/assets/view/*</code>.</li></ul><hr><h2 id="windows-desktop-electron-wrapper" tabindex="-1">Windows Desktop (Electron Wrapper) <a class="header-anchor" href="#windows-desktop-electron-wrapper" aria-label="Permalink to &quot;Windows Desktop (Electron Wrapper)&quot;">​</a></h2><p>Make sure you compiled assets using <code>npm run build:all</code> before running these:</p><h3 id="_1-build-standalone-folder" tabindex="-1">1. Build Standalone Folder <a class="header-anchor" href="#_1-build-standalone-folder" aria-label="Permalink to &quot;1. Build Standalone Folder&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pack-win</span></span></code></pre></div><p>Outputs standalone directory containing executable (<code>AnimeTV.exe</code>):</p><ul><li><strong>x64</strong>: <code>electron/builds/AnimeTV-win32-x64/</code></li><li><strong>ARM64</strong>: <code>electron/builds/AnimeTV-win32-arm64/</code></li></ul><h3 id="_2-generate-setup-wizard-exe" tabindex="-1">2. Generate Setup Wizard (<code>.exe</code>) <a class="header-anchor" href="#_2-generate-setup-wizard-exe" aria-label="Permalink to &quot;2. Generate Setup Wizard (`.exe`)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-win</span></span></code></pre></div><p>Generates setup wizard installer <code>animetv-&lt;version&gt;-setup.exe</code> in <code>electron/builds/</code>.</p><h3 id="_3-generate-portable-zip-archive" tabindex="-1">3. Generate Portable ZIP Archive <a class="header-anchor" href="#_3-generate-portable-zip-archive" aria-label="Permalink to &quot;3. Generate Portable ZIP Archive&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> zip-win</span></span></code></pre></div><p>Produces <code>AnimeTV-win32-x64-portable.zip</code> in <code>electron/builds/</code>.</p><hr><h2 id="android-tv-phone-apks" tabindex="-1">Android (TV &amp; Phone APKs) <a class="header-anchor" href="#android-tv-phone-apks" aria-label="Permalink to &quot;Android (TV &amp; Phone APKs)&quot;">​</a></h2><p>Ensure frontend files are compiled (<code>npm run build:all</code>).</p><h3 id="_1-debug-apk" tabindex="-1">1. Debug APK <a class="header-anchor" href="#_1-debug-apk" aria-label="Permalink to &quot;1. Debug APK&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-debug-apk</span></span></code></pre></div><ul><li><strong>Or directly</strong>: <code>.\\gradlew.bat assembleDebug</code></li><li><strong>Output</strong>: <code>app/build/outputs/apk/debug/</code></li></ul><h3 id="_2-release-apk" tabindex="-1">2. Release APK <a class="header-anchor" href="#_2-release-apk" aria-label="Permalink to &quot;2. Release APK&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build-release-apk</span></span></code></pre></div><ul><li><strong>Or directly</strong>: <code>.\\gradlew.bat assembleRelease</code></li><li><strong>Output</strong>: <code>app/build/outputs/apk/release/</code></li></ul><h3 id="_3-local-deploy-run" tabindex="-1">3. Local Deploy &amp; Run <a class="header-anchor" href="#_3-local-deploy-run" aria-label="Permalink to &quot;3. Local Deploy &amp; Run&quot;">​</a></h3><p>Install APK via ADB onto connected TV/device:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devices</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/build/outputs/apk/debug/app-debug.apk</span></span></code></pre></div><hr><h2 id="command-reference-cheat-sheet" tabindex="-1">Command Reference Cheat Sheet <a class="header-anchor" href="#command-reference-cheat-sheet" aria-label="Permalink to &quot;Command Reference Cheat Sheet&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Platform</th><th style="text-align:left;">Script</th><th style="text-align:left;">Target</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;"><code>npm run build:all</code></td><td style="text-align:left;">Builds assets in <code>app/src/main/assets/view/*</code></td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run pack-win</code></td><td style="text-align:left;">Produces raw executable standalone directories</td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run build-win</code></td><td style="text-align:left;">Produces setup wizard installer executable</td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>npm run zip-win</code></td><td style="text-align:left;">Produces portable standalone ZIP archive</td></tr><tr><td style="text-align:left;"><strong>Android</strong></td><td style="text-align:left;"><code>npm run build-debug-apk</code></td><td style="text-align:left;">Builds debug APK</td></tr><tr><td style="text-align:left;"><strong>Android</strong></td><td style="text-align:left;"><code>npm run build-release-apk</code></td><td style="text-align:left;">Builds release APK</td></tr></tbody></table>',41)])])}const g=a(l,[["render",n]]);export{u as __pageData,g as default};
